-- Modify "roles" table
ALTER TABLE "roles" ADD COLUMN IF NOT EXISTS "permissions_json" jsonb NULL;
-- Create "entitlements" table
CREATE TABLE IF NOT EXISTS "entitlements" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "user_id" bigint NOT NULL,
  "scope_type" character varying NOT NULL DEFAULT 'user',
  "scope_id" bigint NOT NULL,
  "feature_key" character varying NOT NULL,
  "value_json" jsonb NULL,
  "quota_limit" character varying NULL,
  "expires_at" timestamptz NOT NULL,
  "source_subscription_id" bigint NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "entitlement_user_id_feature_key_expires_at" to table: "entitlements"
CREATE INDEX IF NOT EXISTS "entitlement_user_id_feature_key_expires_at" ON "entitlements" ("user_id", "feature_key", "expires_at");
-- Create index "entitlement_source_subscription_id_feature_key" to table: "entitlements"
CREATE UNIQUE INDEX IF NOT EXISTS "entitlement_source_subscription_id_feature_key" ON "entitlements" ("source_subscription_id", "feature_key");
-- Create index "entitlement_scope_type_scope_id_feature_key" to table: "entitlements"
CREATE INDEX IF NOT EXISTS "entitlement_scope_type_scope_id_feature_key" ON "entitlements" ("scope_type", "scope_id", "feature_key");
-- Backfill entitlement cache from active subscription snapshots.
INSERT INTO "entitlements" (
  "created_at",
  "updated_at",
  "user_id",
  "scope_type",
  "scope_id",
  "feature_key",
  "value_json",
  "quota_limit",
  "expires_at",
  "source_subscription_id"
)
SELECT
  NOW(),
  NOW(),
  "s"."user_id",
  'user',
  "s"."user_id",
  "kv"."key",
  jsonb_build_object('value', "kv"."value"),
  CASE
    WHEN "kv"."key" IN ('monthly_token_quota', 'monthly_cost_quota') THEN "kv"."value" #>> '{}'
    ELSE NULL
  END,
  "s"."expires_at",
  "s"."id"
FROM "user_subscriptions" AS "s"
CROSS JOIN LATERAL jsonb_each(COALESCE("s"."entitlements_snapshot_json", '{}'::jsonb)) AS "kv"("key", "value")
WHERE "s"."status" = 'active'
ON CONFLICT ("source_subscription_id", "feature_key") DO NOTHING;
